import torch
import torch.nn as nn
import torch.nn.functional as F


def _gn(num_channels):
    for num_groups in range(min(8, num_channels), 0, -1):
        if num_channels % num_groups == 0:
            return nn.GroupNorm(num_groups, num_channels)
    return nn.GroupNorm(1, num_channels)


class ReflectionConv2d(nn.Module):
    def __init__(self, in_channels, out_channels, kernel_size=3, bias=False, groups=1):
        super().__init__()
        pad = kernel_size // 2
        self.pad = nn.ReflectionPad2d(pad) if pad > 0 else nn.Identity()
        self.conv = nn.Conv2d(
            in_channels,
            out_channels,
            kernel_size=kernel_size,
            padding=0,
            bias=bias,
            groups=groups,
        )

    def forward(self, x):
        return self.conv(self.pad(x))


class ConvBlock(nn.Module):
    def __init__(self, in_channels, out_channels):
        super().__init__()
        self.net = nn.Sequential(
            ReflectionConv2d(in_channels, out_channels, 3, bias=False),
            _gn(out_channels),
            nn.SiLU(inplace=True),
            ReflectionConv2d(out_channels, out_channels, 3, bias=False),
            _gn(out_channels),
            nn.SiLU(inplace=True),
        )

        self.skip = (
            nn.Conv2d(in_channels, out_channels, kernel_size=1, padding=0, bias=False)
            if in_channels != out_channels
            else nn.Identity()
        )

    def forward(self, x):
        return self.net(x) + self.skip(x)


class OmniDirectionalSSMBlock(nn.Module):
    def __init__(self, channels):
        super().__init__()
        self.norm = _gn(channels)

        self.in_proj = nn.Conv2d(channels, channels * 2, kernel_size=1, padding=0)
        self.out_proj = nn.Conv2d(channels, channels, kernel_size=1, padding=0)

        self.h_scan = nn.Conv1d(channels, channels, kernel_size=7, padding=0, groups=channels)
        self.w_scan = nn.Conv1d(channels, channels, kernel_size=7, padding=0, groups=channels)

        self.h_pad = nn.ReflectionPad2d((3, 3, 0, 0))
        self.w_pad = nn.ReflectionPad2d((0, 0, 3, 3))

        self.mix = nn.Sequential(
            ReflectionConv2d(channels, channels, 3, bias=False, groups=channels),
            nn.Conv2d(channels, channels, kernel_size=1, padding=0, bias=False),
            _gn(channels),
            nn.SiLU(inplace=True),
        )

    def forward(self, x):
        residual = x
        x = self.norm(x)
        u, gate = self.in_proj(x).chunk(2, dim=1)

        b, c, h, w = u.shape

        left_right = self.h_scan(self.h_pad(u).permute(0, 2, 1, 3).reshape(b * h, c, w + 6))
        right_left = torch.flip(
            self.h_scan(torch.flip(self.h_pad(u), dims=[3]).permute(0, 2, 1, 3).reshape(b * h, c, w + 6)),
            dims=[2],
        )
        left_right = left_right.reshape(b, h, c, w).permute(0, 2, 1, 3)
        right_left = right_left.reshape(b, h, c, w).permute(0, 2, 1, 3)

        top_bottom = self.w_scan(self.w_pad(u).permute(0, 3, 1, 2).reshape(b * w, c, h + 6))
        bottom_top = torch.flip(
            self.w_scan(torch.flip(self.w_pad(u), dims=[2]).permute(0, 3, 1, 2).reshape(b * w, c, h + 6)),
            dims=[2],
        )
        top_bottom = top_bottom.reshape(b, w, c, h).permute(0, 2, 3, 1)
        bottom_top = bottom_top.reshape(b, w, c, h).permute(0, 2, 3, 1)

        y = (left_right + right_left + top_bottom + bottom_top) * 0.25
        y = self.mix(y) * torch.sigmoid(gate)
        return residual + self.out_proj(y)


class DownBlock(nn.Module):
    def __init__(self, in_channels, out_channels):
        super().__init__()
        self.conv = ConvBlock(in_channels, out_channels)
        self.ssm = OmniDirectionalSSMBlock(out_channels)

    def forward(self, x):
        x = F.avg_pool2d(x, kernel_size=2, stride=2)
        x = self.conv(x)
        return self.ssm(x)


class UpBlock(nn.Module):
    def __init__(self, in_channels, skip_channels, out_channels):
        super().__init__()
        self.reduce = nn.Conv2d(in_channels, out_channels, kernel_size=1, padding=0, bias=False)
        self.conv = ConvBlock(out_channels + skip_channels, out_channels)
        self.ssm = OmniDirectionalSSMBlock(out_channels)

    def forward(self, x, skip):
        x = F.interpolate(x, size=skip.shape[-2:], mode="bilinear", align_corners=False)
        x = self.reduce(x)
        x = torch.cat([x, skip], dim=1)
        x = self.conv(x)
        return self.ssm(x)


class omnidirectional_ssm_unet(nn.Module):
    def __init__(self, in_channels=1, out_channels=1, n_c=16, depth=7):
        super().__init__()

        if depth < 1:
            raise ValueError("depth must be >= 1")

        channels = [min(n_c * (2 ** i), n_c * 8) for i in range(depth)]

        self.stem = ConvBlock(in_channels, channels[0])
        self.stem_ssm = OmniDirectionalSSMBlock(channels[0])

        self.encoder = nn.ModuleList(
            DownBlock(channels[i], channels[i + 1]) for i in range(depth - 1)
        )

        self.bottleneck = nn.Sequential(
            ConvBlock(channels[-1], channels[-1]),
            OmniDirectionalSSMBlock(channels[-1]),
            ConvBlock(channels[-1], channels[-1]),
            OmniDirectionalSSMBlock(channels[-1]),
        )

        self.decoder = nn.ModuleList(
            UpBlock(channels[i], channels[i - 1], channels[i - 1])
            for i in range(depth - 1, 0, -1)
        )

        self.head = nn.Sequential(
            ReflectionConv2d(channels[0], channels[0], 3, bias=False),
            _gn(channels[0]),
            nn.SiLU(inplace=True),
            nn.Conv2d(channels[0], out_channels, kernel_size=1, padding=0),
        )

    def forward(self, x):
        valid = ~torch.isnan(x)
        x_masked = torch.where(torch.isnan(x), torch.zeros_like(x), x)

        skips = []
        y = self.stem(x_masked)
        y = self.stem_ssm(y)
        skips.append(y)

        for block in self.encoder:
            y = block(y)
            skips.append(y)

        y = self.bottleneck(y)

        for block, skip in zip(self.decoder, reversed(skips[:-1])):
            y = block(y, skip)

        y = self.head(y)

        if y.shape[-2:] != x.shape[-2:]:
            y = F.interpolate(y, size=x.shape[-2:], mode="bilinear", align_corners=False)

        if valid.shape[1] != y.shape[1]:
            valid = valid.any(dim=1, keepdim=True).expand_as(y)

        y = torch.where(valid, y, torch.full_like(y, float("nan")))
        return y
